import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"60. On Call Re Call","description":"","frontmatter":{"title":"60. On Call Re Call","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","public-holidays","hours","on-call"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/60-on-call-re-call.md","filePath":"ebas/mspp/hours-of-work/60-on-call-re-call.md"}'),n={name:"ebas/mspp/hours-of-work/60-on-call-re-call.md"};function s(l,e,i,h,c,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_60-on-call-re-call" tabindex="-1">60. On Call Re Call <a class="header-anchor" href="#_60-on-call-re-call" aria-label="Permalink to &quot;60. On Call Re Call&quot;">​</a></h1><p><strong>60.1</strong> On Call Allowance</p><p><strong>a.</strong> All employees except Psychologists, Scientist Directors and Deputy Directors</p><p><strong>(i)</strong> An employee who is rostered on call in respect to any 12-hour period or part thereof during the period commencing from the time of finishing ordinary duty on Monday and the termination of ordinary duty on Friday shall be paid the on call allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> In respect to any 12-hour period or part thereof outside of that described in 60.1a or on any public holiday or part thereof an employee who is rostered on-call shall be paid the weekend and public holiday on-call allowance in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>.</p><p><strong>b.</strong> Psychologists</p><p><strong>(i)</strong> An “on call” allowance of 2.5% of the weekly base rate of pay for their classification shall be paid to an employee in respect to any 12-hour period or part thereof during which the employee is on call during the period commencing from the time of finishing ordinary duty on Monday and the termination of ordinary duty on Friday</p><p><strong>(ii)</strong> The allowance shall be 5% in respect to any other 12-hour period or</p><p><strong>(iii)</strong> A Provisional Psychologist Grade 1 Year 1 - 3 shall who is rostered on-call shall be paid on-call allowances in accordance with clause 60.1a of this Agreement.</p><p><strong>(iv)</strong> Where a Psychologist’s base rate of pay is less than the rate prescribed for all other Employees in <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a>, the Psychologist will receive the allowance identified for all other employees.</p><p><strong>c.</strong> Scientist Director or Deputy Director</p><p><strong>(i)</strong> A Scientist Director or Deputy Director required to be on call outside ordinary hours shall be paid an allowance equal to 10% of their weekly wages for each week during which they are so required. Provided however, that a Scientist Director or Deputy Director not already on call but who substitutes himself or herself on the normal on-call roster of the laboratory concerned shall be paid in accordance with the provisions of 60.1a.</p><p><strong>60.2</strong> Recall</p><p><strong>a.</strong> In the event of an Employee being recalled to duty for any period during an off- duty period such an Employee shall be paid from the time of receiving the recall until the time of finishing such recall duty with a minimum of three hours’ payment for each such recall, at the following rates:</p><p><strong>(i)</strong> Within a spread of twelve hours from the commencement of the last previous period of ordinary duty - time and a half.</p><p><strong>(ii)</strong> Outside a spread of twelve hours from the commencement of the last previous period of ordinary duty - double time.</p><p><strong>b.</strong> An Employee who works so much recall between the termination of their previous rostered ordinary hours of duty and the commencement of their next succeeding period of duty such that they would not have at least ten consecutive hours off duty between those times, shall, subject to this clause, be released after completion of such recall worked until they have had ten consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>c.</strong> If on the instructions of their Employer such an Employee resumes or continues work without having had such ten consecutive hours off duty they shall be paid at the rate of double time until they are released from duty for such rest period and they shall then be entitled to be absent until they have had ten consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence. No Employee shall present for duty on a voluntary basis unless they have had ten consecutive hours (within the meaning of this clause) off duty.</p><p><strong>d.</strong> In the event of any Employee being recalled to duty during an off duty period where such recall is not continuous with the next succeeding rostered period of duty, such Employee shall be paid a minimum of three hours pay consistent with clause 60.2a above.</p><p><strong>e.</strong> In the event of any Employee finishing any period of recall at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer shall provide adequate transport free of cost to the Employee.</p><p><strong>f.</strong> No Employee shall be permitted to be on call in the 24 hour period prior to any change of shift.</p><p><strong>60.3</strong> Recall without returning to the workplace</p><p><strong>a.</strong> Where recall to duty can be managed without the Employee returning to the workplace, for example by telephone, clause 60.1 will not apply and an Employee is recalled to duty by telephone, such an Employee shall be paid a minimum of one hour’s overtime for such recall work.</p><p><strong>b.</strong> For subsequent recalls beyond the first hour, the Employee will be paid a minimum of one hour&#39;s overtime provided that multiple recalls within a discrete hour will not attract an additional payment.</p><p><strong>c.</strong> Where the person on-call is not available, or where there is no person rostered on-call or where the professional advice of an un-rostered Employee is required, the recall allowance shall be paid.</p><p><strong>60.4</strong> Remote On-Call Health services may negotiate local arrangements for remote on-call for Medical Scientists and Medical Physicists. In the event of a Medical Scientist or Medical Physicist being recalled to duty by telephone during an off-duty period and such an</p><p>Employee discharges their duties without returning to the workplace, the provisions of clauses 60.1a, 60.2 and 60.3 shall apply.</p><p><strong>60.5</strong> Crisis Assessment Treatment Team (CATT) On-Call Allowances And Arrangements – Psychiatric Services (CATT only)</p><p><strong>a.</strong> An on-call allowance at the rate prescribe by <a href="/eba/ebas/mspp/schedules/2-rates-of-pay-and-allowances.html">Schedule 2</a> shall be payable to Employees engaged on on-call/recall for the provision of a crisis response (CATT type function) for each on call period of 12 hours or part thereof.</p><p><strong>b.</strong> The allowance includes payment of work performed of up to one hour’s aggregate duration for each on-call period.</p><p><strong>c.</strong> For work performed in excess of an aggregate of one hour during an on-call period, payment shall be made at the normal overtime rate paid at the Employee’s substantive classification and increment level.</p><p><strong>d.</strong> The parties are to regard, telephone attendance as recall to duty.</p><p><strong>e.</strong> Employees are to receive an uninterrupted break of at least ten hours between the end of the recall and the next shift. Where the ten hour break is not observed double time shall be paid until such break is observed.</p><p><strong>f.</strong> The maximum period of on-call for CATT is to be twelve hours, with existing arrangements below the twelve hours not to be disturbed.</p><p><strong>g.</strong> The parties acknowledge the unique nature of on-call requirements for crisis response (CATT-type functions) and that it is not comparable to any other health care arrangement or setting.</p><p><strong>h.</strong> Providing a Grade 1, Provisionally Registered Psychologist will not be rostered on call to provide crisis response without being able to access advice from a psychiatrist or other senior clinicians when recalled to duty.</p><p><strong>60.6</strong> Four Days Clear Of Duty Per Fortnight</p><p><strong>a.</strong> Rosters shall be planned to ensure that Employees receive four clear days per fortnight free from duty including on-call.</p><p><strong>b.</strong> Only where such days free from on-call cannot be provided and Employees are required to be on-call (including telephone recall of greater than one hour and remote on-call):</p><p><strong>(i)</strong> during weekend days or public holidays or on days that the Employee is not rostered for duty; and</p><p><strong>(ii)</strong> are rostered to be on-call for a minimum of two (2) days in every four week cycle over twelve (12) cycles in an anniversary year; such Employee shall receive up to an additional five days leave per anniversary year in accordance with sub-clause c.</p><p><strong>c.</strong> An Employee who is regularly rostered to be on-call in accordance with clauses 60.6b(i) and 60.6b(ii) can accrue such leave on a pro rata basis in accordance with the table below: No. of 4 week roster cycles on call No. of Additional Days Leave Less than 4 0 4 but less than 6 1 6 but less than 8 2 8 but less than 10 3 10 but less than 12 4</p><p>No. of 4 week roster cycles on call No. of Additional Days Leave 12 or more 5</p><p><strong>d.</strong> To determine whether an entitlement arises under sub-clause c the Employer will, between 1 December and 30 December in each year, calculate the number of four week roster cycles worked by the Employee during the 12 month period immediately preceding the date on which the calculation is made, during which the Employee was rostered for on-call duty:</p><p><strong>(i)</strong> on days on which the Employee was not rostered for duty; and</p><p><strong>(ii)</strong> was rostered for on-call duty for a minimum of two days.</p><p><strong>e.</strong> Any leave accrued in accordance with this clause shall be taken by agreement between the Employer and the Employee subject to the operational needs of the health service.</p><p><strong>f.</strong> Any additional leave accrued under this provision shall not attract any projected penalties or annual leave loading.</p><p>HOLIDAYS</p><p>Plain language terms: on-call, recall, called in, called back.</p>',50)])])}const y=o(n,[["render",s]]);export{u as __pageData,y as default};
